<div class="page-head"><div><p class="eyebrow">Історія</p><h1>Відповіді форм</h1></div><a class="button secondary" href="<?= url('/admin/forms') ?>">До форм</a></div>
<form method="get" class="list-tools"><label>Форма<select name="form_id" onchange="this.form.submit()"><option value="0">Усі форми</option><?php foreach ($forms as $form): ?><option value="<?= e((string) $form['id']) ?>" <?= selected((string) $formId,(string) $form['id']) ?>><?= e($form['title']) ?></option><?php endforeach; ?></select></label></form>
<div class="list-panel"><div class="table-scroll"><table><thead><tr><th>Дата</th><th>Форма</th><th>Статус</th><th>Email</th><th>Відповіді</th></tr></thead><tbody>
<?php foreach ($items as $item): $answers=json_decode((string)$item['answers_json'],true)?:[]; $schema=json_decode((string)$item['schema_snapshot_json'],true)?:[]; $labels=array_column($schema,'label','id'); ?><tr><td><?= e($item['created_at']) ?></td><td><?= e($item['form_title']) ?></td><td><span class="status <?= $item['status']==='new'?'warn':'' ?>"><?= e($item['status']) ?></span></td><td><?= e((string)($item['submitter_email']??'')) ?></td><td><?php foreach($answers as $key=>$value): ?><div><strong><?= e($labels[$key]??$key) ?>:</strong> <?= e(is_array($value)?implode(', ',$value):(string)$value) ?></div><?php endforeach; ?></td></tr><?php endforeach; ?>
</tbody></table></div><?php if(!$items): ?><div class="empty-state">Відповідей ще немає.</div><?php endif; ?></div>
